    const float_sw4* __restrict__ up_r = up;
    const float_sw4* __restrict__ u_r  = u;
    const float_sw4* __restrict__ um_r = um;
    float_sw4* __restrict__ u2_r = u2;
    const float_sw4 cdt2i = dt2i;

    size_t stride = nthreads;
    size_t i = myi;

    // Unrolled grid-stride loop to increase ILP and better hide memory latency
    for (; i + 3 * stride < N; i += 4 * stride)
    {
        size_t i0 = i;
        size_t i1 = i + stride;
        size_t i2 = i + 2 * stride;
        size_t i3 = i + 3 * stride;

        float_sw4 up0 = up_r[i0];
        float_sw4 u0  = u_r[i0];
        float_sw4 um0 = um_r[i0];
        u2_r[i0] = cdt2i * (up0 - (float_sw4)2.0 * u0 + um0);

        float_sw4 up1 = up_r[i1];
        float_sw4 u1  = u_r[i1];
        float_sw4 um1 = um_r[i1];
        u2_r[i1] = cdt2i * (up1 - (float_sw4)2.0 * u1 + um1);

        float_sw4 up2 = up_r[i2];
        float_sw4 u2v = u_r[i2];
