__device__ __forceinline__ void shmem_swap(float4 *v1, float4 *v2){
  // Use two register temporaries to minimize shared memory pipeline pressure and RAW hazards.
  float4 a = *v1;
  float4 b = *v2;
  *v1 = b;
  *v2 = a;
}

__device__ __forceinline__ float4 init_val(int i){
