        if (c == 0) {
          u_km2_0 = u_km1_0;
          u_km1_0 = s00;
        } else if (c == 1) {
          u_km2_1 = u_km1_1;
          u_km1_1 = s00;
        } else {
          u_km2_2 = u_km1_2;
          u_km1_2 = s00;
        }
      }
    }
